INSERT INTO `facturacion_pages` VALUES (1,4,'banner',NULL,NULL,NULL,NULL,'facturacionPlus.PNG',NULL,NULL,NULL,1,NULL,'2022-09-06 19:51:15','2024-05-31 04:30:40'),(2,1,'boton','Click para facturar',NULL,'http://picaroscomer.dyndns.org/WebflecHJ/facturacion_01.aspx',NULL,NULL,NULL,NULL,NULL,2,NULL,'2022-09-06 19:51:57','2024-04-30 02:02:36'),(3,4,'titulo','Instrucciones para facturación electrónica.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,3,NULL,'2022-09-06 19:52:14','2024-05-31 04:29:58'),(4,4,'subtitulo',NULL,NULL,'<p><big><strong>Una vez dentro de la p&aacute;gina, nos posicionamos en la pesta&ntilde;a Facturar Ticket, rellenando los datos de la siguiente manera.</strong></big></p>',NULL,NULL,NULL,NULL,NULL,4,NULL,'2022-09-06 19:52:31','2024-05-31 04:28:29'),(5,1,'textoImagen',NULL,NULL,NULL,'<ol>\r\n	<li><big>Ingrese el&nbsp;<strong>RFC</strong>&nbsp;de su empresa.</big></li>\r\n	<li><big>Introduzca la serie de su ticket.</big></li>\r\n	<li><big>Ingrese el No. De su ticket (Sin comas)</big></li>\r\n	<li><big>Ingrese el No. De&nbsp;<strong>TR#&nbsp;</strong>de su ticket.</big></li>\r\n</ol>\r\n\r\n<p><big>Y procedemos a darle clic en continuar</big></p>','fact1.PNG',NULL,NULL,NULL,5,NULL,'2022-09-06 19:54:16','2023-10-05 18:34:40'),(6,1,'subtitulo',NULL,NULL,'<p><big><strong>Posteriormente nos redireccionar&aacute;&nbsp;a un&nbsp;apartado donde&nbsp;se rellenan los datos respectivos para su factura.</strong></big></p>',NULL,NULL,NULL,NULL,NULL,6,NULL,'2022-09-06 19:54:43','2022-09-07 22:56:34'),(7,1,'textoImagen',NULL,NULL,NULL,'<ol>\r\n	<li><big>Verifique que el&nbsp;<strong>RFC</strong>&nbsp;corresponde al de su empresa.</big></li>\r\n	<li><big>Ingrese el nombre de su&nbsp;<strong>Raz&oacute;n social sin su r&eacute;gimen capital</strong></big></li>\r\n	<li><big>Ingrese los datos de su direcci&oacute;n de acuerdo a su&nbsp;<strong>Constancia de situaci&oacute;n fiscal</strong></big></li>\r\n	<li><big>Ingrese la direcci&oacute;n&nbsp;del&nbsp;<strong>CORREO ELECTR&Oacute;NICO&nbsp;</strong>al cual se enviar&aacute; su factura en Formato&nbsp;<strong>PDF y XML</strong>.</big></li>\r\n	<li><big>Este campo se habilitar&aacute;&nbsp;<strong>si su m&eacute;todo de pago es con tarjeta</strong>&nbsp;y deber&aacute; ingresar los&nbsp;<strong>&uacute;ltimos 4 d&iacute;gitos</strong>&nbsp;de la tarjeta con la que realiz&oacute; su pago.</big></li>\r\n	<li><big><strong>Seleccione</strong>&nbsp;<strong>el</strong>&nbsp;<strong>R&eacute;gimen Fiscal</strong>&nbsp;seg&uacute;n su Constancia de Situaci&oacute;n Fiscal.</big></li>\r\n	<li><big>Seleccione el&nbsp;<strong>Uso que se le dara al&nbsp;CFDI.</strong></big></li>\r\n	<li><big>Antes de hacer clic en&nbsp;<strong>Facturar&nbsp;</strong>se le recomienda&nbsp;<strong>VERIFICAR SUS DATOS.</strong></big></li>\r\n</ol>','fact.PNG',NULL,NULL,NULL,7,NULL,'2022-09-06 19:55:13','2022-09-07 22:56:57'),(8,1,'boton','Click para Facturar',NULL,'http://picaroscomer.dyndns.org/WebflecHJ/facturacion_01.aspx',NULL,NULL,NULL,NULL,NULL,8,NULL,'2022-09-06 19:55:41','2024-04-30 02:02:41'),(9,1,'subtitulo',NULL,NULL,'<p><big><strong>Si presenta alg&uacute;n detalle durante el proceso, con gusto le atenderemos al tel&eacute;fono 953 530 00 87</strong></big></p>',NULL,NULL,NULL,NULL,NULL,20,NULL,'2022-09-06 19:56:09','2022-12-29 22:37:00'),(10,1,'titulo','Consultar factura',NULL,NULL,NULL,NULL,NULL,NULL,NULL,10,NULL,'2022-09-07 20:35:17','2022-09-07 20:35:17'),(13,1,'subtitulo',NULL,NULL,'<p><big><strong>Puede&nbsp;consultar y descargar una copia de su factura en formato PDF y XML seleccionando&nbsp;una de estas dos opciones.</strong></big></p>',NULL,NULL,NULL,NULL,NULL,11,NULL,'2022-09-07 22:11:52','2022-09-07 22:11:52'),(14,1,'textoImagen',NULL,NULL,NULL,'<p><big><strong>Opcion 1 (Por ticket de compra):&nbsp;</strong></big></p>\r\n\r\n<ul>\r\n	<li><big>Ingrese la serie&nbsp;de su ticket.</big></li>\r\n	<li><big>Ingrese el No. De su ticket (Sin comas).</big></li>\r\n	<li><big>Ingrese el No. De <strong>TR# </strong>de su ticket.&nbsp;</big></li>\r\n</ul>\r\n\r\n<p><big><strong>Opcion 2 (Por factura emitida):</strong></big></p>\r\n\r\n<ul>\r\n	<li><big>Ingrese su&nbsp;RFC.</big></li>\r\n	<li><big>Ingrese su numero de factura.</big></li>\r\n</ul>\r\n\r\n<p><big>Y procedemos a darle clic en continuar.</big></p>','image.png',NULL,NULL,NULL,12,NULL,'2022-09-07 22:12:18','2023-10-05 18:35:07'),(15,1,'subtitulo',NULL,NULL,'<p><big><strong>Posteriormente nos aparece la pantalla donde podra descargar manualmente su PDF,&nbsp;XML o ambos segun se requiera.</strong></big></p>',NULL,NULL,NULL,NULL,NULL,13,NULL,'2022-09-07 22:12:33','2022-09-07 22:39:45'),(16,1,'textoImagen',NULL,NULL,NULL,'<ol>\r\n	<li><big>Mostrar&aacute; su factura en formato PDF.</big></li>\r\n	<li><big>Mostrar&aacute; su factura en formato&nbsp;</big><big>XML.</big></li>\r\n	<li><big>Aqui podr&aacute;&nbsp;colocar una direcci&oacute;n de correo electr&oacute;nico para el reenvio de la factura en formato&nbsp;PDF y XML.</big></li>\r\n</ol>','image (1).png',NULL,NULL,NULL,14,NULL,'2022-09-07 22:12:51','2022-09-07 22:12:51'),(17,1,'boton','Consultar factura',NULL,'http://picaroscomer.dyndns.org/WebflecHJ/cfdCons.aspx',NULL,NULL,NULL,NULL,NULL,14,NULL,'2022-09-07 22:13:50','2022-09-07 22:18:23');
