INSERT INTO `miempresas` VALUES (1,3,'banner','Banner','null','nosotros.jpg',NULL,1,NULL,'2022-07-06 01:35:19','2022-07-06 01:35:19'),(2,1,'historia','NUESTRA HISTORIA','Super Plus, fundada en el año 2010, en la ciudad de Huajuapan de León Oaxaca, respaldada por la experiencia de Cervezas Modelo en la Mixteca S.A. de C.V. empresa con liderazgo en el sector cervecero.\r\nActualmente contamos con 50 tiendas  distribuidas en la mixteca Oaxaqueña, brindando  servicio las 24 horas del día los 365 días del año,  con una experiencia de 13 años en el mercado, esmerándos en llevar a nuestros clientes productos y servicios  de calidad.','fachada_cb2[1].png','fachada.png',2,NULL,'2022-07-06 01:36:05','2023-10-05 18:32:45'),(3,1,'mision',NULL,'Satisfacer las necesidades de los clientes proporcionando un Plus a su Día.','mision.png','super plus palomita.png',4,NULL,'2022-07-06 01:38:53','2022-07-06 19:35:26'),(4,4,'vision',NULL,'Ser la mejor opción en tienda de conveniencia y posicionar la marca en diferentes mercados.','vision.png','super plus palomita.png',4,NULL,'2022-07-06 01:42:07','2024-05-31 04:11:01'),(5,1,'valores',NULL,'<strong>El cliente es el jefe:</strong> En Super Plus el cliente es lo más importante, trabajamos para su completa satisfacción. <br>\r\n<strong>Ser mejor cada día:</strong> Fijarse objetivos día a día, con una mentalidad innovadora basándose en hechos y datos para cumplir las expectativas de nuestros clientes y de la empresa. <br>\r\n<strong>Trabajo en equipo:</strong> En un gran equipo hay unión, cada integrante hace su aporte aprovechando la diversidad de ideas, habilidades y talentos. <br>\r\n<strong>Gente con la gente:</strong> Crear un ambiente de empatía en colaboración, reconocimiento, diversidad y respeto.','valores.png','super plus palomita.png',5,NULL,'2022-07-06 01:42:41','2023-10-05 18:33:16'),(6,1,'titulo','ACERCA DE NOSOTROS','ACERCA DE NOSOTROS','super_plus.png',NULL,3,NULL,'2022-07-06 19:35:02','2022-07-06 19:35:16');
/*!40000 ALTER TABLE `miempresas` ENABLE KEYS */;
UNLOCK TABLES;

